package be.schaubroeck.lpb.rkm.rekenmotor.bruto;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonCodeCalculator;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.RkmCoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.BijdragePercentagesFactoryImp;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.BerekenTerugbetalingSocialeBijdragen;
import be.schaubroeck.lpb.rkm.rekenmotor.service.BijdragePercentagesFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.SleutelGegevensSingleOpper;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.enumtypes.Janeen;
import be.schaubroeck.lpb.tools.enumtypes.KedefFormuletype;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.service.LooncodeInclusiefService;
import com.google.common.collect.ImmutableSet;
import lombok.Getter;

import java.math.BigDecimal;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.ACHTERSTAL_PRE_OMSCHAKELING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.KEDSPECIAALTYPE_COMPENSATOIRE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.KEDSPECIAALTYPE_DIPLOMA_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.KEDSPECIAALTYPE_HASTA_KEY;

@Getter
public class LoonCodeCalculatorFactory {

    private static final Set<LoonElement> EMPTY_SET = ImmutableSet.of();

    private final ConstantManager constantManager;
    private final RegulManager regulManager;
    private final LoonCodeManager loonCodeManager;
    private final LooncodeInclusiefService looncodeInclusiefService;
    private final RkmCoreHrConfiguratie rkmCoreHrConfiguratie;
    protected BijdragePercentagesFactory bijdragePercentagesFactory;

    public LoonCodeCalculatorFactory(
            ConstantManager constantManager, RegulManager regulManager, LoonCodeManager loonCodeManager,
            NlpGlobalService globalService, RkmCoreHrConfiguratie rkmCoreHrConfiguratie) {
        this.constantManager = constantManager;
        this.regulManager = regulManager;
        this.loonCodeManager = loonCodeManager;
        this.looncodeInclusiefService = globalService.getLooncodeInclusiefService();
        this.bijdragePercentagesFactory = new BijdragePercentagesFactoryImp(constantManager, globalService);
        this.rkmCoreHrConfiguratie = rkmCoreHrConfiguratie;
    }

    public LoonCodeCalculator genereerLoonCodeCalculator(Opper opper, AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd) {
        return genereerLoonCodeCalculator(opper, aardKodeExtensie, rekenTijd, null, null);
    }

    public LoonCodeCalculator genereerLoonCodeCalculator(
            Opper opper, AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd, Set<LoonElement> supplementenFase1, BigDecimal index) {
        SleutelGegevens gegevens = new SleutelGegevensSingleOpper(opper);
        return genereerLoonCodeCalculator(gegevens, aardKodeExtensie, rekenTijd, supplementenFase1, index);
    }

    public LoonCodeCalculator genereerLoonCodeCalculator(SleutelGegevens gegevens, AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd) {
        return genereerLoonCodeCalculator(gegevens, aardKodeExtensie, rekenTijd, null, null);
    }

    public LoonCodeCalculator genereerLoonCodeCalculator(
            SleutelGegevens gegevens, AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd, Set<LoonElement> supplementenFase1, BigDecimal index) {
        if (aardKodeExtensie.getHardGecodeerd().equals(Janeen.JA.getCode())) {
            return bepaalCalculatorHardGecodeerd(gegevens, aardKodeExtensie, rekenTijd);
        } else {
            return bepaalCalculatorFormuleType(gegevens, aardKodeExtensie, rekenTijd, supplementenFase1, index);
        }
    }

    private LoonCodeCalculator bepaalCalculatorHardGecodeerd(SleutelGegevens gegevens, AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd) {
        if (!aardKodeExtensie.behoortTotGroep(ACHTERSTAL_PRE_OMSCHAKELING_KEY)) {
            if (aardKodeExtensie.behoortTotGroep(KEDSPECIAALTYPE_HASTA_KEY)) {
                return new LoonCodeCalculatorHasta(gegevens, aardKodeExtensie, rekenTijd, this);
            } else if (aardKodeExtensie.behoortTotGroep(KEDSPECIAALTYPE_DIPLOMA_KEY)) {
                return new LoonCodeCalculatorDiploma(gegevens, aardKodeExtensie, rekenTijd, this);
            } else if (aardKodeExtensie.behoortTotGroep(KEDSPECIAALTYPE_COMPENSATOIRE_KEY)) {
                return new LoonCodeCalculatorTriviaal();
            } else if (BerekenTerugbetalingSocialeBijdragen.isLoonElementTerugbetalingRsz(aardKodeExtensie)) {
                return new LoonCodeCalculatorTriviaal();
            }
        } else {
            regulManager.doRegulException(gegevens.getOpdracht(), Regulkode.ONVERWACHTE_APO_LOONCODE);
        }
        return null;
    }

    private LoonCodeCalculator bepaalCalculatorFormuleType(
            SleutelGegevens gegevens, AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd,
            Set<LoonElement> supplementenFase1, BigDecimal index) {
        if (supplementenFase1 == null) {
            supplementenFase1 = EMPTY_SET;
        }
        KedefFormuletype formuleType = aardKodeExtensie.getFormuleType();
        switch (formuleType) {
            case REG_WG:
            case REG_WG_FF:
                return new LoonCodeCalculatorRegelingWerkgever(gegevens, aardKodeExtensie, rekenTijd, supplementenFase1, index, this);
            case REG_WN:
            case REG_WN_FF:
            case ONR_XxY:
                return new LoonCodeCalculatorTriviaal();
            case ONR_WG_UL:
                return
                        new LoonCodeCalculatorOnregelmatigWerkgeverUurloon(gegevens, aardKodeExtensie, rekenTijd, supplementenFase1, index, this);
            case ANDERE:
            default:
                regulManager.doRegulException(gegevens.getOpdracht(), Regulkode.FORMULETYPE_NIET_GEPROGRAMMEERD);
                return null;

        }
    }
}
